// MARK: - Message Types & Validation

enum NativeMessageType: String, CaseIterable {
    case cameraAccess = "cameraAccess"
    case pushNotification = "pushNotification"
    case inAppPurchase = "inAppPurchase"
    case hapticFeedback = "hapticFeedback"
    case getDeviceInfo = "getDeviceInfo"
}

struct NativeMessage {
    let type: NativeMessageType
    let payload: [String: Any]
    let callbackId: String?
    
    init?(from body: Any) {
        guard let dict = body as? [String: Any],
              let action = dict["action"] as? String,
              let messageType = NativeMessageType(rawValue: action) else {
            return nil
        }
        self.type = messageType
        self.payload = dict["payload"] as? [String: Any] ?? [:]
        self.callbackId = dict["callbackId"] as? String
    }
}

