    static let contentSecurityPolicy = """
    default-src 'self' https://app.yourdomain.com https://cdn.yourdomain.com; \
    script-src 'self' https://app.yourdomain.com https://cdn.yourdomain.com; \
    style-src 'self' 'unsafe-inline' https://cdn.yourdomain.com; \
    img-src 'self' https: data:; \
