    // Max payload size in bytes
    static let maxPayloadSize: Int = 4096
    
    static func isOriginAllowed(_ url: URL?) -> Bool {
        guard let url = url,
              let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            return false
        }
        
        let origin = "\(scheme)://\(url.host ?? "")"
        return allowedOrigins.contains(origin)
    }
    
    static func isNavigationAllowed(_ url: URL?) -> Bool {
        guard let url = url else { return false }
        
        // Allow about:blank for initial loads
        if url.absoluteString == "about:blank" { return true }
        
        // Allow app store links for IAP
        if url.scheme == "itms-appss" || url.host == "apps.apple.com" {
            return true
        }
        
        return isOriginAllowed(url)
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private var timestamps: [Date] = []
    private let maxCount: Int
    private let interval: TimeInterval
    private let queue = DispatchQueue(label: "com.app.ratelimiter")
    
    init(maxCount: Int, interval: TimeInterval = 1.0) {
        self.maxCount = maxCount
        self.interval = interval
    }
    
    func shouldAllow() -> Bool {
        return queue.sync {
            let now = Date()
            timestamps = timestamps.filter { now.timeIntervalSince($0) < interval }
            if timestamps.count < maxCount {
                timestamps.append(now)
                return true
            }
            return false
        }
    }
}

