// MARK: - WKScriptMessageHandler (via LeakAvoider)

private final class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(
        _ userContentController: WKUserContentController,
        didReceive message: WKScriptMessage
    ) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(
        _ userContentController: WKUserContentController,
        didReceive message: WKScriptMessage
    ) {
        // Security: Verify message handler name
        guard message.name == WebViewSecurityConfig.messageHandlerName else {
            print("[Security] Unknown message handler: \(message.name)")
            return
        }
        
        // Security: Verify origin
        guard WebViewSecurityConfig.isOriginAllowed(message.frameInfo.request.url ?? webView.url) else {
            print("[Security] Message from unauthorized origin: \(String(describing: message.frameInfo.request.url))")
            return
        }
        
        // Security: Only accept messages from main frame
        guard message.frameInfo.isMainFrame else {
            print("[Security] Message from non-main frame rejected")
            return
        }
        
        // Rate limiting
        guard rateLimiter.shouldAllow() else {
            print("[Security] Rate limit exceeded")
            if let dict = message.body as? [String: Any],
               let callbackId = dict["callbackId"] as? String {
                sendCallbackToWeb(callbackId: callbackId, success: false, data: ["error": "Rate limit exceeded"])
            }
            return
        }
        
        // Payload size validation
        guard validatePayloadSize(message.body) else {
            print("[Security] Payload too large")
            if let dict = message.body as? [String: Any],
               let callbackId = dict["callbackId"] as? String {
                sendCallbackToWeb(callbackId: callbackId, success: false, data: ["error": "Payload too large"])
            }
            return
        }
        
        // Parse and validate message
        guard let nativeMessage = NativeMessage(from: message.body) else {
            print("[Security] Invalid message format")
            return
        }
        
        handleNativeMessage(nativeMessage)
    }
    
    private func handleNativeMessage(_ message: NativeMessage) {
        switch message.type {
        case .cameraAccess:
            handleCameraAccess(callbackId: message.callbackId)
            
        case .pushNotification:
            handlePushNotification(payload: message.payload, callbackId: message.callbackId)
            
        case .inAppPurchase:
            handleInAppPurchase(payload: message.payload, callbackId: message.callbackId)
            
        case .hapticFeedback:
            handleHapticFeedback(payload: message.payload)
            
        case .getDeviceInfo:
            handleGetDeviceInfo(callbackId: message.callbackId)
        }
    }
}

// MARK: - Native Feature Handlers

extension HybridWebViewController {
    
    private func handleCameraAccess(callbackId: String?) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            presentCamera(callbackId: callbackId)
            
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    if granted {
                        self?.presentCamera(callbackId: callbackId)
                    } else {
                        self?.sendCallbackToWeb(
                            callbackId: callbackId,
                            success: false,
                            data: ["error": "Camera access denied"]
                        )
                    }
                }
            }
            
        case .denied, .restricted:
            sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "Camera access denied. Please enable in Settings."]
            )
            
        @unknown default:
            sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "Unknown camera authorization status"]
            )
        }
    }
    
    private func presentCamera(callbackId: String?) {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "Camera not available"]
            )
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.modalPresentationStyle = .fullScreen
        
        // Store callback ID for later use
        objc_setAssociatedObject(
            picker,
            &AssociatedKeys.callbackId,
            callbackId,
            .OBJC_ASSOCIATION_RETAIN_NONATOMIC
        )
        
        present(picker, animated: true)
    }
    
    private func handlePushNotification(payload: [String: Any], callbackId: String?) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            DispatchQueue.main.async {
                switch settings.authorizationStatus {
                case .authorized, .provisional:
                    self?.sendCallbackToWeb(
                        callbackId: callbackId,
                        success: true,
                        data: ["status": "authorized"]
                    )
                    
                case .notDetermined:
                    UNUserNotificationCenter.current().requestAuthorization(
                        options: [.alert, .badge, .sound]
                    ) { granted, error in
                        DispatchQueue.main.async {
                            if granted {
                                UIApplication.shared.registerForRemoteNotifications()
                                self?.sendCallbackToWeb(
                                    callbackId: callbackId,
                                    success: true,
                                    data: ["status": "authorized"]
                                )
                            } else {
                                self?.sendCallbackToWeb(
                                    callbackId: callbackId,
                                    success: false,
                                    data: ["error": error?.localizedDescription ?? "Permission denied"]
                                )
                            }
                        }
                    }
                    
                case .denied:
                    self?.sendCallbackToWeb(
                        callbackId: callbackId,
                        success: false,
                        data: ["error": "Notifications denied. Please enable in Settings."]
                    )
                    
                case .ephemeral:
                    self?.sendCallbackToWeb(
                        callbackId: callbackId,
                        success: true,
                        data: ["status": "ephemeral"]
                    )
                    
                @unknown default:
                    self?.sendCallbackToWeb(
                        callbackId: callbackId,
                        success: false,
                        data: ["error": "Unknown notification status"]
                    )
                }
            }
        }
    }
    
    private func handleInAppPurchase(payload: [String: Any], callbackId: String?) {
        guard let productId = payload["productId"] as? String,
              !productId.isEmpty,
              productId.count <= 128,
              productId.range(of: "^[a-zA-Z0-9._]+$", options: .regularExpression) != nil else {
            sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "Invalid product ID"]
            )
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "In-app purchases are not allowed on this device"]
            )
            return
        }
        
        pendingPurchaseCallbackId = callbackId
        
        // If we already have the product info, purchase directly
        if let product = loadedProducts[productId] {
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
            return
        }
        
        // Otherwise fetch product info first
        let request = SKProductsRequest(productIdentifiers: Set([productId]))
        request.delegate = self
        productsRequest = request
        request.start()
    }
    
    private func handleHapticFeedback(payload: [String: Any]) {
        let style = payload["style"] as? String ?? "medium"
        
        switch style {
        case "light":
            let generator = UIImpactFeedbackGenerator(style: .light)
            generator.impactOccurred()
        case "medium":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        case "heavy":
            let generator = UIImpactFeedbackGenerator(style: .heavy)
            generator.impactOccurred()
        case "success":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
        case "warning":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.warning)
        case "error":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.error)
        case "selection":
            let generator = UISelectionFeedbackGenerator()
            generator.selectionChanged()
        default:
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        }
    }
    
    private func handleGetDeviceInfo(callbackId: String?) {
        let device = UIDevice.current
        let info: [String: Any] = [
            "platform": "iOS",
            "systemVersion": device.systemVersion,
            "model": device.model,
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown",
            "isSimulator": {
                #if targetEnvironment(simulator)
                return true
                #else
                return false
                #endif
            }()
        ]
        sendCallbackToWeb(callbackId: callbackId, success: true, data: info)
    }
}

