// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(
        _ webView: WKWebView,
        decidePolicyFor navigationAction: WKNavigationAction,
        decisionHandler: @escaping (WKNavigationActionPolicy) -> Void
    ) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Allow App Store links to open externally
        if url.scheme == "itms-appss" || url.host == "apps.apple.com" {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Block non-allowed origins
        guard WebViewSecurityConfig.isNavigationAllowed(url) else {
            print("[Security] Blocked navigation to: \(url.absoluteString)")
            decisionHandler(.cancel)
            return
        }
        
        // Block opening new windows via target="_blank" — load in same webview
        if navigationAction.targetFrame == nil {
            webView.load(navigationAction.request)
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(
        _ webView: WKWebView,
        decidePolicyFor navigationResponse: WKNavigationResponse,
        decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void
    ) {
        guard let httpResponse = navigationResponse.response as? HTTPURLResponse else {
            decisionHandler(.allow)
            return
        }
        
        // Verify the response is from an allowed origin
        if let url = httpResponse.url,
           !WebViewSecurityConfig.isNavigationAllowed(url) {
            print("[Security] Blocked response from: \(url.absoluteString)")
            decisionHandler(.cancel)
            return
        }
        
        // Check for valid HTTP status codes
        if httpResponse.statusCode >= 400 {
            print("[WebView] HTTP error: \(httpResponse.statusCode)")
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        errorView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        errorView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        showError(error)
    }
    
    func webView(
        _ webView: WKWebView,
        didFailProvisionalNavigation navigation: WKNavigation!,
        withError error: Error
    ) {
        activityIndicator.stopAnimating()
        showError(error)
    }
    
    func webView(
        _ webView: WKWebView,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        // SSL Pinning could be implemented here for additional security
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    private func showError(_ error: Error) {
        let nsError = error as NSError
        // Don't show error for cancelled navigations
        guard nsError.code != NSURLErrorCancelled else { return }
        
        errorView.isHidden = false
        errorLabel.text = "Unable to load content.\n\(error.localizedDescription)"
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    // Handle JavaScript alerts
    func webView(
        _ webView: WKWebView,
        runJavaScriptAlertPanelWithMessage message: String,
        initiatedByFrame frame: WKFrameInfo,
        completionHandler: @escaping () -> Void
    ) {
        guard WebViewSecurityConfig.isOriginAllowed(frame.request.url) else {
            completionHandler()
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirms
    func webView(
        _ webView: WKWebView,
        runJavaScriptConfirmPanelWithMessage message: String,
        initiatedByFrame frame: WKFrameInfo,
        completionHandler: @escaping (Bool) -> Void
    ) {
        guard WebViewSecurityConfig.isOriginAllowed(frame.request.url) else {
            completionHandler(false)
            return
        }
        
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Prevent popups / new windows
    func webView(
        _ webView: WKWebView,
        createWebViewWith configuration: WKWebViewConfiguration,
        for navigationAction: WKNavigationAction,
        windowFeatures: WKWindowFeatures
    ) -> WKWebView? {
        // Load in the same webview instead of opening a new one
        if let url = navigationAction.request.url,
           WebViewSecurityConfig.isNavigationAllowed(url) {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - UIImagePickerControllerDelegate

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(
        _ picker: UIImagePickerController,
        didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]
    ) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        
        picker.dismiss(animated: true) { [weak self] in
            if let image = info[.originalImage] as? UIImage,
               let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                self?.sendCallbackToWeb(
                    callbackId: callbackId,
                    success: true,
                    data: [
                        "imageBase64": "data:image/jpeg;base64,\(base64String)",
                        "width": image.size.width,
                        "height": image.size.height
                    ]
                )
            } else {
                self?.sendCallbackToWeb(
                    callbackId: callbackId,
                    success: false,
                    data: ["error": "Failed to process image"]
                )
            }
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, &AssociatedKeys.callbackId) as? String
        
        picker.dismiss(animated: true) { [weak self] in
            self?.sendCallbackToWeb(
                callbackId: callbackId,
                success: false,
                data: ["error": "User cancelled"]
            )
        }
    }
}

// MARK: - SKProductsRequestDelegate

extension HybridWebViewController: SKProductsRequestDelegate {
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        guard let product = response.products.first else {
            sendCallbackToWeb(
                callbackId: pendingPurchaseCallbackId,
                success: false,
                data: ["error": "Product not found"]
            )
            pendingPurchaseCallbackId = nil
            return
        }
        
        loadedProducts[product.productIdentifier] = product
        
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(self)
        SKPaymentQueue.default().add(payment)
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        sendCallbackToWeb(
            callbackId: pendingPurchaseCallbackId,
            success: false,
            data: ["error": "Failed to fetch product: \(error.localizedDescription)"]
        )
        pendingPurchaseCallbackId = nil
    }
}

// MARK: - SKPaymentTransactionObserver

extension HybridWebViewController: SKPaymentTransactionObserver {
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let receiptData = Bundle.main.appStoreReceiptURL
                    .flatMap { try? Data(contentsOf: $0) }?
                    .base64EncodedString() ?? ""
                
                sendCallbackToWeb(
                    callbackId: pendingPurchaseCallbackId,
                    success: true,
                    data: [
                        "transactionId": transaction.transactionIdentifier ?? "",
                        "productId": transaction.payment.productIdentifier,
                        "receipt": receiptData
                    ]
                )
                queue.finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                sendCallbackToWeb(
                    callbackId: pendingPurchaseCallbackId,
                    success: false,
                    data: ["error": errorMessage]
                )
                queue.finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .restored:
                queue.finishTransaction(transaction)
                
            case .deferred, .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
}

// MARK: - Public API for External Use

extension HybridWebViewController {
    
    /// Navigate to a specific path within the allowed domain
    func navigateTo(path: String) {
        guard var components = URLComponents(url: WebViewSecurityConfig.homeURL, resolvingAgainstBaseURL: false) else {
            return
        }
        
        // Sanitize path
        let sanitizedPath = path.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? path
        components.path = sanitizedPath
        
        guard let url = components.url,
              WebViewSecurityConfig.isNavigationAllowed(url) else {
            print("[Security] Navigation to path blocked: \(path)")
            return
        }
        
        webView.load(URLRequest(url: url))
    }
    
    /// Execute JavaScript in the web view (use with caution)
    func evaluateJavaScript(_ script: String, completion: ((Any?, Error?) -> Void)? = nil) {
        webView.evaluateJavaScript(script, completionHandler: completion)
    }
    
    /// Clear all website data
    func clearWebsiteData(completion: (() -> Void)? = nil) {
        let dataStore = WKWebsiteDataStore.default()
        let dataTypes = WKWebsiteDataStore.allWebsiteDataTypes()
        let dateFrom = Date(timeIntervalSince1970: 0)
        dataStore.removeData(ofTypes: dataTypes, modifiedSince: dateFrom) {
            completion?()
        }
    }
    
    /// Reload the current page
    func reload() {
        webView.reload()
    }
    
    /// Go back in navigation history
    func goBack() {
        if webView.canGoBack {
            webView.goBack()
        }
    }
}